func safeFileName(name string) string {
	trimmed := strings.TrimSpace(name)
	if trimmed == "" {
		return "project"
	}
	replacer := strings.NewReplacer(" ", "_", "/", "_", "\\", "_", ":", "_")
	return replacer.Replace(trimmed)
}

func maxInt(a, b int) int {
	if a > b {
		return a
	}
	return b
}

