	fd := dialog.NewFileSave(func(writer fyne.URIWriteCloser, err error) {
		if err != nil {
			dialog.ShowError(err, ui.window)
			return
		}
		if writer == nil {
			return
		}
		defer writer.Close()

		ui.touchProject()
		raw, err := ui.project.Marshal()
		if err != nil {
			dialog.ShowError(err, ui.window)
			return
		}
		if _, err := writer.Write(raw); err != nil {
