+		lineGap = maxInt(int(float64(lineGap)*fitFactor), 4)
+		padding = maxInt(int(float64(padding)*fitFactor), 12)
+		charWidth = cols*cellW + maxInt(cols-1, 0)*gapX
+		charHeight = rows*cellH + maxInt(rows-1, 0)*gapY
+	}
+
+	return displayLayout{
+		cols:       cols,
+		rows:       rows,
+		cellWidth:  cellW,
+		cellHeight: cellH,
+		cellGapX:   gapX,
+		cellGapY:   gapY,
